class Solution {
public:
    int canBeTypedWords(string text, string brokenLetters) {
        int count = 0;
        string word;
        for (char c : text) {
            if (c == ' ') {
                if (word.find_first_not_of(brokenLetters) != string::npos) {
                    count++;
                }
                word.clear();
            } else {
                word += c;
            }
        }
        if (word.find_first_not_of(brokenLetters) != string::npos) {
            count++;
        }
        return count;
    }
};
```

